cuts = as.integer(cuts); 

#make an empty list
mod.list <- list();
for(i in 1:length(cuts)) 
{ 
      if (i==1)
      {
	start = 1;
      }
      else
      {
   	start = cuts[i-1];
      }
      end = cuts[i];
      mod.list[[i]] = lm(rawData[[2]][start:end] ~
